function solve(s) {
    // 1. Calculate frequencies of all characters
    const freqMap = new Map();
    for (const char of s) {
        freqMap.set(char, (freqMap.get(char) || 0) + 1);
    }

    // Helper function to get the mirror character
    const getMirror = (char) => {
        const code = char.charCodeAt(0);

        if (char >= 'a' && char <= 'z') {
            // Alphabet: 'a' (97) -> 'z' (122), 'b' (98) -> 'y' (121)
            // Mirror position: 25 - (position from 'a')
            // 'a' is 0-th, 'z' is 25-th.
            // New char code = 'a' code + (25 - (code - 'a' code))
            const offset = code - 'a'.charCodeAt(0);
            const mirrorOffset = 25 - offset;
            return String.fromCharCode('a'.charCodeAt(0) + mirrorOffset);
        } else if (char >= '0' && char <= '9') {
            // Digits: '0' -> '9', '1' -> '8'
            const digit = parseInt(char);
            const mirrorDigit = 9 - digit;
            return String(mirrorDigit);
        }
        return null; // Should not happen based on problem constraints
    };

    let totalDifference = 0;
    const processedPairs = new Set();

    // 2. Iterate over all unique characters present in s
    for (const char of freqMap.keys()) {
        if (processedPairs.has(char)) {
