            // If it did happen, we'd calculate |freq(c) - freq(c)| = 0.
            totalDifference += 0;
            processedPairs.add(char);
            continue;
        }

        // Check if the mirror character is also in the string (or if we need to account for it being absent)
        const freqC = freqMap.get(char);
        const freqM = freqMap.get(mirrorChar) || 0;

        // Mark both characters as processed for this pair calculation
        processedPairs.add(char);
        processedPairs.add(mirrorChar);

